    "html": "<div class=\"banner\" id=\"banner\">\n  <div class=\"left\">\n    <div class=\"icon-wrap\">🎟️</div>\n    <div class=\"banner-text\">\n      <strong>Oferta Especial Ativa! <span class=\"badge-hot\">NOVO</span></strong>\n      <span>Compre 3 bilhetes e leve 5 – só até hoje!</span>\n    </div>\n  </div>\n  <div class=\"right\">\n    <div class=\"timer\">\n      <svg width=\"14\" height=\"14\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" viewBox=\"0 0 24 24\"><circle cx=\"12\" cy=\"12\" r=\"10\"/><polyline points=\"12 6 12 12 16 14\"/></svg>\n      <span id=\"t\">23:59:59</span>\n    </div>\n    <a href=\"#\" class=\"btn itu-accept\">Garantir Agora</a>\n    <button class=\"close-btn itu-close\" onclick=\"document.getElementById('banner').style.display='none'\">✕</button>\n  </div>\n</div>",
    "css": "*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n  body { font-family: 'Inter', sans-serif; background: #0f1117; }\n\n  .banner {\n    background: linear-gradient(135deg, #1a0a3d 0%, #2d1b69 50%, #1a0a3d 100%);\n    border-bottom: 1px solid rgba(108,99,255,.3);\n    padding: 14px 2rem;\n    display: flex; align-items: center; justify-content: space-between; gap: 1rem;\n    position: relative; overflow: hidden;\n  }\n  .banner::before {\n    content: ''; position: absolute; inset: 0;\n    background: linear-gradient(90deg, transparent, rgba(108,99,255,.08), transparent);\n    animation: shimmer 3s infinite;\n  }\n  @keyframes shimmer { 0%{transform:translateX(-100%)} 100%{transform:translateX(100%)} }\n\n  .left { display: flex; align-items: center; gap: 1rem; }\n  .icon-wrap {\n    width: 40px; height: 40px; border-radius: 10px;\n    background: linear-gradient(135deg, #6c63ff, #a855f7);\n    display: flex; align-items: center; justify-content: center; flex-shrink: 0;\n    font-size: 1.25rem;\n  }\n  .banner-text strong { color: #f1f5f9; font-size: .95rem; display: block; }\n  .banner-text span { color: #a78bfa; font-size: .8rem; }\n\n  .badge-hot {\n    background: #ef4444; color: #fff; font-size: .65rem; font-weight: 700;\n    padding: 2px 8px; border-radius: 99px; margin-left: 8px;\n    animation: blink 1.5s infinite;\n  }\n  @keyframes blink { 0%,100%{opacity:1}50%{opacity:.6} }\n\n  .right { display: flex; align-items: center; gap: 1rem; flex-shrink: 0; }\n\n  .timer { display: flex; align-items: center; gap: 6px; color: #f59e0b; font-size: .85rem; font-weight: 700; }\n  .timer svg { animation: spin 2s linear infinite; }\n  @keyframes spin { to{transform:rotate(360deg)} }\n\n  .btn {\n    padding: 8px 20px; border-radius: 8px; border: none; cursor: pointer;\n    font-family: 'Inter', sans-serif; font-size: .8rem; font-weight: 700;\n    background: linear-gradient(135deg, #6c63ff, #a855f7); color: #fff;\n    transition: transform .15s, box-shadow .15s; text-decoration: none; white-space: nowrap;\n    box-shadow: 0 4px 16px rgba(108,99,255,.4);\n  }\n  .btn:hover { transform: translateY(-1px); box-shadow: 0 6px 20px rgba(108,99,255,.6); }\n\n  .close-btn {\n    background: none; border: none; color: #64748b; cursor: pointer;\n    font-size: 1rem; padding: 4px; line-height: 1;\n    transition: color .2s;\n  }\n  .close-btn:hover { color: #e2e8f0; }\n\n  @media(max-width:600px) { .timer { display: none; } }",
    "js": "let s = 23*3600+59*60+59;\n  const el = document.getElementById('t');\n  setInterval(()=>{\n    if(s>0)s--;\n    const h=Math.floor(s/3600), m=Math.floor(s%3600/60), sec=s%60;\n    el.textContent=String(h).padStart(2,'0')+':'+String(m).padStart(2,'0')+':'+String(sec).padStart(2,'0');\n  },1000);",
    "supportsScript": true,
