    "html": "<div class=\"testimonials\">\n  <div class=\"testimonials-header\">\n    <h2>💬 O Que Nossos Ganhadores Dizem</h2>\n    <p class=\"sub\">Mais de 1.200 ganhadores verificados</p>\n  </div>\n\n  <div class=\"carousel\">\n    <div class=\"slides\" id=\"slides\">\n\n      <div class=\"slide\">\n        <div class=\"stars\">★★★★★</div>\n        <p class=\"quote\">\"Não acreditei quando recebi a ligação! Comprei apenas 5 bilhetes e ganhei o carro. Processo super transparente e rápido!\"</p>\n        <div class=\"author\">\n          <div class=\"avatar\" style=\"background:linear-gradient(135deg,#6c63ff,#a855f7)\">MR</div>\n          <div class=\"author-info\">\n            <div class=\"name\">Marcos Rodrigues</div>\n            <div class=\"meta\">São Paulo, SP</div>\n          </div>\n          <span class=\"badge-won\">🏆 Ganhou o Carro</span>\n        </div>\n      </div>\n\n      <div class=\"slide\">\n        <div class=\"stars\">★★★★★</div>\n        <p class=\"quote\">\"Recebi meus R$ 2.000 em menos de 24 horas após o resultado. Tudo na mão, sem burocracia. Já comprei bilhetes para o próximo!\"</p>\n        <div class=\"author\">\n          <div class=\"avatar\" style=\"background:linear-gradient(135deg,#10b981,#059669)\">AF</div>\n          <div class=\"author-info\">\n            <div class=\"name\">Ana Ferreira</div>\n            <div class=\"meta\">Belo Horizonte, MG</div>\n          </div>\n          <span class=\"badge-won\">💰 Ganhou R$2.000</span>\n        </div>\n      </div>\n\n      <div class=\"slide\">\n        <div class=\"stars\">★★★★★</div>\n        <p class=\"quote\">\"Minha primeira vez participando e já ganhei a moto! Indiquei para toda minha família. É sério, honesto e vale muito a pena!\"</p>\n        <div class=\"author\">\n          <div class=\"avatar\" style=\"background:linear-gradient(135deg,#f59e0b,#ef4444)\">CS</div>\n          <div class=\"author-info\">\n            <div class=\"name\">Carlos Silva</div>\n            <div class=\"meta\">Fortaleza, CE</div>\n          </div>\n          <span class=\"badge-won\">🏍️ Ganhou a Moto</span>\n        </div>\n      </div>\n\n    </div>\n  </div>\n\n  <div class=\"controls\">\n    <button class=\"prev-btn\" id=\"prev\" aria-label=\"Anterior\">\n      <svg width=\"14\" height=\"14\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\" viewBox=\"0 0 24 24\"><polyline points=\"15 18 9 12 15 6\"/></svg>\n    </button>\n    <div class=\"dots\" id=\"dots\">\n      <div class=\"dot active\" data-i=\"0\"></div>\n      <div class=\"dot\" data-i=\"1\"></div>\n      <div class=\"dot\" data-i=\"2\"></div>\n    </div>\n    <button class=\"next-btn\" id=\"next\" aria-label=\"Próximo\">\n      <svg width=\"14\" height=\"14\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\" viewBox=\"0 0 24 24\"><polyline points=\"9 18 15 12 9 6\"/></svg>\n    </button>\n  </div>\n</div>",
    "css": "*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n  body { font-family: 'Inter', sans-serif; background: #0f1117; padding: 2rem; display: flex; align-items: center; justify-content: center; min-height: 100vh; }\n\n  .testimonials { max-width: 560px; width: 100%; }\n  .testimonials-header { text-align: center; margin-bottom: 1.75rem; }\n  h2 { font-size: 1.4rem; font-weight: 800; color: #f1f5f9; margin-bottom: .25rem; }\n  .sub { font-size: .875rem; color: #94a3b8; }\n\n  .carousel { position: relative; overflow: hidden; border-radius: 16px; }\n\n  .slides { display: flex; transition: transform .5s cubic-bezier(.4,0,.2,1); }\n\n  .slide {\n    min-width: 100%; background: #1a1d27; border: 1px solid #2e3347; border-radius: 16px;\n    padding: 2rem; display: flex; flex-direction: column; gap: 1rem;\n  }\n\n  .stars { color: #f59e0b; font-size: 1rem; }\n  .quote { font-size: .95rem; color: #cbd5e1; line-height: 1.75; font-style: italic; }\n\n  .author { display: flex; align-items: center; gap: .875rem; margin-top: .5rem; }\n  .avatar { width: 46px; height: 46px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-weight: 800; color: #fff; font-size: 1rem; flex-shrink: 0; }\n  .author-info .name { font-weight: 700; color: #f1f5f9; font-size: .9rem; }\n  .author-info .meta { font-size: .75rem; color: #64748b; }\n\n  .badge-won {\n    display: inline-flex; align-items: center; gap: 5px; margin-left: auto;\n    background: rgba(16,185,129,.15); border: 1px solid rgba(16,185,129,.3);\n    color: #10b981; font-size: .7rem; font-weight: 700; padding: 4px 10px; border-radius: 99px;\n  }\n\n  /* CONTROLS */\n  .controls { display: flex; align-items: center; justify-content: center; gap: 1rem; margin-top: 1.25rem; }\n  .prev-btn, .next-btn {\n    width: 36px; height: 36px; border-radius: 50%; border: 1px solid #2e3347;\n    background: #1a1d27; color: #94a3b8; cursor: pointer;\n    display: flex; align-items: center; justify-content: center;\n    transition: border-color .15s, color .15s;\n  }\n  .prev-btn:hover, .next-btn:hover { border-color: #6c63ff; color: #6c63ff; }\n\n  .dots { display: flex; gap: 6px; }\n  .dot { width: 7px; height: 7px; border-radius: 50%; background: #2e3347; cursor: pointer; transition: background .2s, transform .2s; }\n  .dot.active { background: #6c63ff; transform: scale(1.3); }",
    "js": "let current = 0;\n  const slides = document.getElementById('slides');\n  const dots = document.querySelectorAll('.dot');\n  const total = 3;\n  function go(i){\n    current = (i + total) % total;\n    slides.style.transform = `translateX(-${current * 100}%)`;\n    dots.forEach((d,j)=>d.classList.toggle('active', j===current));\n  }\n  document.getElementById('prev').onclick = ()=>go(current-1);\n  document.getElementById('next').onclick = ()=>go(current+1);\n  dots.forEach(d=>d.addEventListener('click',()=>go(+d.dataset.i)));\n  setInterval(()=>go(current+1), 5000);",
